import json
import time
from typing import Any

import boto3
import requests
from botocore.exceptions import ClientError
from loguru import logger

DEFAULT_REGION = "ap-southeast-2"


# --- Deploy helpers ---


def get_existing_api_key_provider_arn(
    client: Any, credential_provider_name: str
) -> str | None:
    """Return ARN of existing API key credential provider by name, or None."""
    paginator = client.get_paginator("list_api_key_credential_providers")
    for page in paginator.paginate():
        for provider in page.get("credentialProviders", []):
            if provider.get("name") == credential_provider_name:
                return provider["credentialProviderArn"]
    return None


def create_or_get_api_key_credential_provider(
    credential_provider_name: str,
    api_key: str,
    region: str = DEFAULT_REGION,
) -> str:
    """Create API key credential provider or return existing ARN."""
    client = boto3.client(service_name="bedrock-agentcore-control", region_name=region)
    try:
        response = client.create_api_key_credential_provider(
            name=credential_provider_name, apiKey=api_key
        )
        return response["credentialProviderArn"]
    except ClientError as e:
        if e.response["Error"]["Code"] != "ValidationException":
            raise
        if "already exists" not in (e.response.get("Error", {}).get("Message") or ""):
            raise
        existing_arn = get_existing_api_key_provider_arn(
            client, credential_provider_name
        )
        if existing_arn is None:
            raise ValueError(
                f"Credential provider '{credential_provider_name}' already exists "
                "but could not be found in list"
            ) from e
        return existing_arn


def create_or_get_gateway(
    gateway_name: str,
    role_arn: str,
    client_id: str,
    cognito_discovery_url: str,
    region: str = DEFAULT_REGION,
) -> tuple[str, str]:
    """Create gateway or return existing gateway id and url."""
    gateway_client = boto3.client("bedrock-agentcore-control", region_name=region)
    auth_config = {
        "customJWTAuthorizer": {
            "allowedClients": [client_id],
            "discoveryUrl": cognito_discovery_url,
        }
    }
    try:
        logger.info(f"Creating gateway '{gateway_name}'")
        create_response = gateway_client.create_gateway(
            name=gateway_name,
            roleArn=role_arn,
            protocolType="MCP",
            authorizerType="CUSTOM_JWT",
            authorizerConfiguration=auth_config,
            description="AgentCore Gateway with OpenAPI target",
        )
        gateway_id = create_response["gatewayId"]
        logger.info(
            f"Gateway created: id={gateway_id} url={create_response['gatewayUrl']}"
        )
        return gateway_id, create_response["gatewayUrl"]
    except ClientError as e:
        if e.response["Error"]["Code"] != "ConflictException":
            raise
        logger.info(f"Gateway '{gateway_name}' already exists, retrieving")
        list_response = gateway_client.list_gateways(maxResults=100)
        existing = next(
            (
                i
                for i in list_response.get("items", [])
                if i.get("name") == gateway_name
            ),
            None,
        )
        if existing is None:
            raise ValueError(
                f"Gateway '{gateway_name}' exists but could not be found in list"
            ) from e
        gateway_id = existing["gatewayId"]
        get_response = gateway_client.get_gateway(gatewayIdentifier=gateway_id)
        logger.info(
            f"Using existing gateway: id={gateway_id} url={get_response['gatewayUrl']}"
        )
        return gateway_id, get_response["gatewayUrl"]


def wait_for_gateway_active(
    gateway_id: str,
    region: str = DEFAULT_REGION,
    poll_interval_sec: int = 10,
    max_wait_sec: int = 300,
) -> None:
    """Wait until gateway status is READY (required before adding targets)."""
    gateway_client = boto3.client("bedrock-agentcore-control", region_name=region)
    waited = 0
    last_status = "UNKNOWN"
    ready_statuses = {"READY"}
    failed_statuses = {"FAILED", "UPDATE_UNSUCCESSFUL", "DELETING"}
    while waited < max_wait_sec:
        resp = gateway_client.get_gateway(gatewayIdentifier=gateway_id)
        last_status = resp.get("status", "").upper()
        if last_status in ready_statuses:
            logger.info(f"Gateway {gateway_id} is READY (waited {waited}s)")
            return
        if last_status in failed_statuses:
            reasons = resp.get("statusReasons") or []
            raise RuntimeError(
                f"Gateway {gateway_id} status={last_status} reasons={reasons}"
            )
        logger.info(
            f"Gateway {gateway_id} status={last_status}, waiting {poll_interval_sec}s before recheck"
        )
        time.sleep(poll_interval_sec)
        waited += poll_interval_sec
    raise TimeoutError(
        f"Gateway {gateway_id} did not become READY within {max_wait_sec}s (last status: {last_status})"
    )


def load_openapi_spec_json(openapi_spec_path: str) -> str:
    """Load OpenAPI spec from path and return as JSON string."""
    with open(openapi_spec_path, encoding="utf-8") as f:
        spec = json.load(f)
    return json.dumps(spec)


def upsert_gateway_target(
    gateway_id: str,
    target_name: str,
    credential_provider_name: str,
    api_key_arn: str,
    openapi_spec_path: str,
    region: str = DEFAULT_REGION,
) -> None:
    """Upsert gateway target: update in-place if it already exists, otherwise create."""
    gateway_client = boto3.client("bedrock-agentcore-control", region_name=region)
    openapi_payload = load_openapi_spec_json(openapi_spec_path)
    api_key_config = [
        {
            "credentialProviderType": "API_KEY",
            "credentialProvider": {
                "apiKeyCredentialProvider": {
                    "credentialParameterName": credential_provider_name,
                    "providerArn": api_key_arn,
                    "credentialLocation": "HEADER",
                }
            },
        },
    ]
    target_config = {
        "mcp": {
            "openApiSchema": {
                "inlinePayload": openapi_payload,
            }
        }
    }

    existing_target_id = next(
        (
            item["targetId"]
            for item in gateway_client.list_gateway_targets(
                gatewayIdentifier=gateway_id, maxResults=100
            ).get("items", [])
            if item.get("name") == target_name
        ),
        None,
    )

    if existing_target_id:
        logger.info(f"Updating existing target '{target_name}' on gateway {gateway_id}")
        gateway_client.update_gateway_target(
            gatewayIdentifier=gateway_id,
            targetId=existing_target_id,
            name=target_name,
            description="Calculator API",
            credentialProviderConfigurations=api_key_config,
            targetConfiguration=target_config,
        )
    else:
        logger.info(f"Creating target '{target_name}' on gateway {gateway_id}")
        for attempt in range(1, 11):
            try:
                gateway_client.create_gateway_target(
                    name=target_name,
                    gatewayIdentifier=gateway_id,
                    description="Calculator API",
                    credentialProviderConfigurations=api_key_config,
                    targetConfiguration=target_config,
                )
                break
            except ClientError as e:
                code = e.response.get("Error", {}).get("Code")
                message = e.response.get("Error", {}).get("Message") or ""
                if code == "ValidationException" and "CREATING status" in message:
                    logger.info(
                        f"Gateway not ready for targets yet (attempt {attempt}/10), sleeping 10s"
                    )
                    time.sleep(10)
                    continue
                raise
    logger.info(f"Target '{target_name}' upserted on gateway {gateway_id}")


def run_deploy(
    gateway_name: str,
    gateway_role_name: str,
    user_pool_name: str,
    resource_gateway_id: str,
    resource_gateway_name: str,
    client_name: str,
    scopes: list[dict[str, Any]],
    credential_provider_name: str,
    api_key: str,
    openapi_spec_path: str,
    target_name: str,
    region: str = DEFAULT_REGION,
) -> dict[str, str]:
    """Upsert gateway and all dependencies (role, Cognito, API key, target).

    Returns a dict with gateway_url, user_pool_id, client_id, client_secret,
    scope_string, and cognito_token_url — everything needed to call get_token.
    """
    # 1. IAM role
    logger.info("Ensuring IAM role for gateway")
    role_response = create_agentcore_gateway_role(gateway_role_name)
    role_arn = role_response["Role"]["Arn"]

    # 2. Cognito user pool, resource server, m2m client
    logger.info("Ensuring Cognito user pool, resource server, and m2m client")
    cognito_client = boto3.client("cognito-idp", region_name=region)
    user_pool_id = get_or_create_user_pool(cognito_client, user_pool_name)
    if user_pool_id is None:
        raise ValueError("Failed to get or create Cognito user pool")
    get_or_create_resource_server(
        cognito_client,
        user_pool_id,
        resource_gateway_id,
        resource_gateway_name,
        scopes,
    )
    client_id, client_secret = get_or_create_m2m_client(
        cognito_client, user_pool_id, client_name, resource_gateway_id
    )
    scope_string = (
        f"{resource_gateway_id}/gateway:read {resource_gateway_id}/gateway:write"
    )
    cognito_discovery_url = f"https://cognito-idp.{region}.amazonaws.com/{user_pool_id}/.well-known/openid-configuration"
    cognito_token_url = f"https://{user_pool_id.replace('_', '').lower()}.auth.{region}.amazoncognito.com/oauth2/token"

    # 3. Gateway (create or get existing)
    gateway_id, gateway_url = create_or_get_gateway(
        gateway_name, role_arn, client_id, cognito_discovery_url, region
    )
    wait_for_gateway_active(gateway_id, region)

    # 4. API key credential provider
    logger.info("Ensuring API key credential provider")
    api_key_arn = create_or_get_api_key_credential_provider(
        credential_provider_name, api_key, region
    )

    # 5. Target upsert
    upsert_gateway_target(
        gateway_id,
        target_name,
        credential_provider_name,
        api_key_arn,
        openapi_spec_path,
        region,
    )
    return {
        "gateway_url": gateway_url,
        "user_pool_id": user_pool_id,
        "client_id": client_id,
        "client_secret": client_secret,
        "scope_string": scope_string,
        "cognito_token_url": cognito_token_url,
    }


def setup_cognito_user_pool():
    # Initialize Cognito client
    cognito_client = boto3.client("cognito-idp", region_name=DEFAULT_REGION)

    try:
        # Create User Pool
        user_pool_response = cognito_client.create_user_pool(
            PoolName="MCPServerPool", Policies={"PasswordPolicy": {"MinimumLength": 8}}
        )
        pool_id = user_pool_response["UserPool"]["Id"]

        # Create App Client
        app_client_response = cognito_client.create_user_pool_client(
            UserPoolId=pool_id,
            ClientName="MCPServerPoolClient",
            GenerateSecret=False,
            ExplicitAuthFlows=["ALLOW_USER_PASSWORD_AUTH", "ALLOW_REFRESH_TOKEN_AUTH"],
        )
        client_id = app_client_response["UserPoolClient"]["ClientId"]

        # Create User
        cognito_client.admin_create_user(
            UserPoolId=pool_id,
            Username="testuser",
            TemporaryPassword="Temp123!",
            MessageAction="SUPPRESS",
        )

        # Set Permanent Password
        cognito_client.admin_set_user_password(
            UserPoolId=pool_id,
            Username="testuser",
            Password="MyPassword123!",
            Permanent=True,
        )

        # Authenticate User and get Access Token
        auth_response = cognito_client.initiate_auth(
            ClientId=client_id,
            AuthFlow="USER_PASSWORD_AUTH",
            AuthParameters={"USERNAME": "testuser", "PASSWORD": "MyPassword123!"},
        )
        bearer_token = auth_response["AuthenticationResult"]["AccessToken"]

        # Output the required values
        logger.info(f"Pool id: {pool_id}")
        logger.info(
            f"Discovery URL: https://cognito-idp.{DEFAULT_REGION}.amazonaws.com/{pool_id}/.well-known/openid-configuration"
        )
        logger.info(f"Client ID: {client_id}")
        logger.info(f"Bearer Token: {bearer_token}")

        # Return values if needed for further processing
        return {
            "pool_id": pool_id,
            "client_id": client_id,
            "bearer_token": bearer_token,
            "discovery_url": f"https://cognito-idp.{DEFAULT_REGION}.amazonaws.com/{pool_id}/.well-known/openid-configuration",
        }

    except Exception as e:
        logger.info(f"Error: {e}")
        return None


def get_or_create_user_pool(cognito: Any, USER_POOL_NAME: str) -> str | None:
    response = cognito.list_user_pools(MaxResults=60)
    for pool in response["UserPools"]:
        if pool["Name"] == USER_POOL_NAME:
            user_pool_id = pool["Id"]
            response = cognito.describe_user_pool(UserPoolId=user_pool_id)

            # Get the domain from user pool description
            user_pool = response.get("UserPool", {})
            domain = user_pool.get("Domain")

            if domain:
                region = (
                    user_pool_id.split("_")[0]
                    if "_" in user_pool_id
                    else DEFAULT_REGION
                )
                domain_url = f"https://{domain}.auth.{region}.amazoncognito.com"
                logger.info(
                    f"Found domain for user pool {user_pool_id}: {domain} ({domain_url})"
                )
            else:
                logger.info(f"No domains found for user pool {user_pool_id}")
            return pool["Id"]
    logger.info("Creating new user pool")
    created = cognito.create_user_pool(PoolName=USER_POOL_NAME)
    user_pool_id = created["UserPool"]["Id"]
    user_pool_id_without_underscore_lc = user_pool_id.replace("_", "").lower()
    cognito.create_user_pool_domain(
        Domain=user_pool_id_without_underscore_lc, UserPoolId=user_pool_id
    )
    logger.info("Domain created as well")
    return created["UserPool"]["Id"]


def get_or_create_resource_server(
    cognito: Any,
    user_pool_id: str,
    RESOURCE_SERVER_ID: str,
    RESOURCE_SERVER_NAME: str,
    SCOPES: list[dict[str, Any]],
) -> str:
    try:
        cognito.describe_resource_server(
            UserPoolId=user_pool_id, Identifier=RESOURCE_SERVER_ID
        )
        return RESOURCE_SERVER_ID
    except ClientError as err:
        if err.response["Error"]["Code"] != "ResourceNotFoundException":
            raise
        logger.info("creating new resource server")
        cognito.create_resource_server(
            UserPoolId=user_pool_id,
            Identifier=RESOURCE_SERVER_ID,
            Name=RESOURCE_SERVER_NAME,
            Scopes=SCOPES,
        )
    return RESOURCE_SERVER_ID


def get_or_create_m2m_client(cognito, user_pool_id, CLIENT_NAME, RESOURCE_SERVER_ID):
    response = cognito.list_user_pool_clients(UserPoolId=user_pool_id, MaxResults=60)
    for client in response["UserPoolClients"]:
        if client["ClientName"] == CLIENT_NAME:
            describe = cognito.describe_user_pool_client(
                UserPoolId=user_pool_id, ClientId=client["ClientId"]
            )
            return client["ClientId"], describe["UserPoolClient"]["ClientSecret"]
    logger.info("creating new m2m client")
    created = cognito.create_user_pool_client(
        UserPoolId=user_pool_id,
        ClientName=CLIENT_NAME,
        GenerateSecret=True,
        AllowedOAuthFlows=["client_credentials"],
        AllowedOAuthScopes=[
            f"{RESOURCE_SERVER_ID}/gateway:read",
            f"{RESOURCE_SERVER_ID}/gateway:write",
        ],
        AllowedOAuthFlowsUserPoolClient=True,
        SupportedIdentityProviders=["COGNITO"],
        ExplicitAuthFlows=["ALLOW_REFRESH_TOKEN_AUTH"],
    )
    return created["UserPoolClient"]["ClientId"], created["UserPoolClient"][
        "ClientSecret"
    ]


def get_token(
    user_pool_id: str,
    client_id: str,
    client_secret: str,
    scope_string: str,
    region: str = DEFAULT_REGION,
) -> dict:
    try:
        user_pool_id_without_underscore = user_pool_id.replace("_", "")
        url = f"https://{user_pool_id_without_underscore}.auth.{region}.amazoncognito.com/oauth2/token"
        headers = {"Content-Type": "application/x-www-form-urlencoded"}
        data = {
            "grant_type": "client_credentials",
            "client_id": client_id,
            "client_secret": client_secret,
            "scope": scope_string,
        }
        response = requests.post(url, headers=headers, data=data)
        response.raise_for_status()
        return response.json()

    except requests.exceptions.RequestException as err:
        return {"error": str(err)}


def create_agentcore_role(agent_name):
    iam_client = boto3.client("iam")
    agentcore_role_name = f"agentcore-{agent_name}-role"
    region = DEFAULT_REGION
    account_id = boto3.client("sts").get_caller_identity()["Account"]
    role_policy = {
        "Version": "2012-10-17",
        "Statement": [
            {
                "Sid": "BedrockPermissions",
                "Effect": "Allow",
                "Action": [
                    "bedrock:InvokeModel",
                    "bedrock:InvokeModelWithResponseStream",
                ],
                "Resource": "*",
            },
            {
                "Effect": "Allow",
                "Action": ["logs:DescribeLogStreams", "logs:CreateLogGroup"],
                "Resource": [
                    f"arn:aws:logs:{region}:{account_id}:log-group:/aws/bedrock-agentcore/runtimes/*"
                ],
            },
            {
                "Effect": "Allow",
                "Action": ["logs:DescribeLogGroups"],
                "Resource": [f"arn:aws:logs:{region}:{account_id}:log-group:*"],
            },
            {
                "Effect": "Allow",
                "Action": ["logs:CreateLogStream", "logs:PutLogEvents"],
                "Resource": [
                    f"arn:aws:logs:{region}:{account_id}:log-group:/aws/bedrock-agentcore/runtimes/*:log-stream:*"
                ],
            },
            {
                "Effect": "Allow",
                "Action": [
                    "xray:PutTraceSegments",
                    "xray:PutTelemetryRecords",
                    "xray:GetSamplingRules",
                    "xray:GetSamplingTargets",
                ],
                "Resource": ["*"],
            },
            {
                "Effect": "Allow",
                "Resource": "*",
                "Action": "cloudwatch:PutMetricData",
                "Condition": {
                    "StringEquals": {"cloudwatch:namespace": "bedrock-agentcore"}
                },
            },
            {
                "Effect": "Allow",
                "Resource": "*",
                "Action": "s3:GetObject",
            },
            {"Effect": "Allow", "Resource": "*", "Action": "lambda:InvokeFunction"},
            {
                "Effect": "Allow",
                "Action": ["bedrock-agentcore:*", "iam:PassRole"],
                "Resource": "*",
            },
            {
                "Sid": "GetAgentAccessToken",
                "Effect": "Allow",
                "Action": [
                    "bedrock-agentcore:GetWorkloadAccessToken",
                    "bedrock-agentcore:GetWorkloadAccessTokenForJWT",
                    "bedrock-agentcore:GetWorkloadAccessTokenForUserId",
                ],
                "Resource": [
                    f"arn:aws:bedrock-agentcore:{region}:{account_id}:workload-identity-directory/default",
                    f"arn:aws:bedrock-agentcore:{region}:{account_id}:workload-identity-directory/default/workload-identity/{agent_name}-*",
                ],
            },
        ],
    }
    assume_role_policy_document = {
        "Version": "2012-10-17",
        "Statement": [
            {
                "Sid": "AssumeRolePolicy",
                "Effect": "Allow",
                "Principal": {"Service": "bedrock-agentcore.amazonaws.com"},
                "Action": "sts:AssumeRole",
                "Condition": {
                    "StringEquals": {"aws:SourceAccount": f"{account_id}"},
                    "ArnLike": {
                        "aws:SourceArn": f"arn:aws:bedrock-agentcore:{region}:{account_id}:*"
                    },
                },
            }
        ],
    }

    assume_role_policy_document_json = json.dumps(assume_role_policy_document)
    role_policy_document = json.dumps(role_policy)
    # Create IAM Role for the Lambda function
    try:
        agentcore_iam_role = iam_client.create_role(
            RoleName=agentcore_role_name,
            AssumeRolePolicyDocument=assume_role_policy_document_json,
        )

        # Pause to make sure role is created
        time.sleep(10)
    except iam_client.exceptions.EntityAlreadyExistsException:
        logger.info(
            f"Role {agentcore_role_name} already exists, deleting and recreating"
        )
        policies = iam_client.list_role_policies(
            RoleName=agentcore_role_name, MaxItems=100
        )
        for policy_name in policies["PolicyNames"]:
            iam_client.delete_role_policy(
                RoleName=agentcore_role_name, PolicyName=policy_name
            )
        iam_client.delete_role(RoleName=agentcore_role_name)
        agentcore_iam_role = iam_client.create_role(
            RoleName=agentcore_role_name,
            AssumeRolePolicyDocument=assume_role_policy_document_json,
        )

    logger.info(f"Attaching inline policy AgentCorePolicy to {agentcore_role_name}")
    try:
        iam_client.put_role_policy(
            PolicyDocument=role_policy_document,
            PolicyName="AgentCorePolicy",
            RoleName=agentcore_role_name,
        )
    except Exception as e:
        logger.warning(f"Put role policy failed: {e}")

    return agentcore_iam_role


def create_agentcore_gateway_role(gateway_name):
    iam_client = boto3.client("iam")
    agentcore_gateway_role_name = f"agentcore-{gateway_name}-role"
    region = DEFAULT_REGION
    account_id = boto3.client("sts").get_caller_identity()["Account"]
    role_policy = {
        "Version": "2012-10-17",
        "Statement": [
            {
                "Sid": "VisualEditor0",
                "Effect": "Allow",
                "Action": [
                    "bedrock-agentcore:*",
                    "bedrock:*",
                    "agent-credential-provider:*",
                    "iam:PassRole",
                    "secretsmanager:GetSecretValue",
                    "lambda:InvokeFunction",
                ],
                "Resource": "*",
            }
        ],
    }

    assume_role_policy_document = {
        "Version": "2012-10-17",
        "Statement": [
            {
                "Sid": "AssumeRolePolicy",
                "Effect": "Allow",
                "Principal": {"Service": "bedrock-agentcore.amazonaws.com"},
                "Action": "sts:AssumeRole",
                "Condition": {
                    "StringEquals": {"aws:SourceAccount": f"{account_id}"},
                    "ArnLike": {
                        "aws:SourceArn": f"arn:aws:bedrock-agentcore:{region}:{account_id}:*"
                    },
                },
            }
        ],
    }

    assume_role_policy_document_json = json.dumps(assume_role_policy_document)
    role_policy_document = json.dumps(role_policy)

    def policy_docs_match(a: str, b: str) -> bool:
        try:
            return json.dumps(json.loads(a), sort_keys=True) == json.dumps(
                json.loads(b), sort_keys=True
            )
        except (json.JSONDecodeError, TypeError):
            return False

    try:
        agentcore_iam_role = iam_client.create_role(
            RoleName=agentcore_gateway_role_name,
            AssumeRolePolicyDocument=assume_role_policy_document_json,
        )
        time.sleep(10)
    except iam_client.exceptions.EntityAlreadyExistsException:
        existing = iam_client.get_role(RoleName=agentcore_gateway_role_name)
        assume_match = policy_docs_match(
            existing["Role"]["AssumeRolePolicyDocument"],
            assume_role_policy_document_json,
        )
        policy_match = False
        try:
            pol = iam_client.get_role_policy(
                RoleName=agentcore_gateway_role_name, PolicyName="AgentCorePolicy"
            )
            policy_match = policy_docs_match(
                pol["PolicyDocument"], role_policy_document
            )
        except iam_client.exceptions.NoSuchEntityException:
            pass
        if assume_match and policy_match:
            logger.info(
                f"IAM role {agentcore_gateway_role_name} already exists and matches config, skipping"
            )
            return existing
        logger.info(f"IAM role {agentcore_gateway_role_name} exists, recreating")
        for policy_name in iam_client.list_role_policies(
            RoleName=agentcore_gateway_role_name, MaxItems=100
        ).get("PolicyNames", []):
            iam_client.delete_role_policy(
                RoleName=agentcore_gateway_role_name, PolicyName=policy_name
            )
        iam_client.delete_role(RoleName=agentcore_gateway_role_name)
        agentcore_iam_role = iam_client.create_role(
            RoleName=agentcore_gateway_role_name,
            AssumeRolePolicyDocument=assume_role_policy_document_json,
        )

    logger.info(
