def create_agentcore_gateway_role_s3_smithy(gateway_name):
    iam_client = boto3.client("iam")
    agentcore_gateway_role_name = f"agentcore-{gateway_name}-role"
    region = DEFAULT_REGION
    account_id = boto3.client("sts").get_caller_identity()["Account"]
    role_policy = {
        "Version": "2012-10-17",
        "Statement": [
            {
                "Sid": "VisualEditor0",
                "Effect": "Allow",
                "Action": [
                    "bedrock-agentcore:*",
                    "bedrock:*",
                    "agent-credential-provider:*",
                    "iam:PassRole",
                    "secretsmanager:GetSecretValue",
                    "lambda:InvokeFunction",
                    "s3:*",
                ],
                "Resource": "*",
            }
        ],
    }

    assume_role_policy_document = {
        "Version": "2012-10-17",
        "Statement": [
            {
                "Sid": "AssumeRolePolicy",
                "Effect": "Allow",
                "Principal": {"Service": "bedrock-agentcore.amazonaws.com"},
                "Action": "sts:AssumeRole",
                "Condition": {
                    "StringEquals": {"aws:SourceAccount": f"{account_id}"},
                    "ArnLike": {
                        "aws:SourceArn": f"arn:aws:bedrock-agentcore:{region}:{account_id}:*"
                    },
                },
            }
        ],
    }

    assume_role_policy_document_json = json.dumps(assume_role_policy_document)

    role_policy_document = json.dumps(role_policy)
    # Create IAM Role for the Lambda function
    try:
        agentcore_iam_role = iam_client.create_role(
            RoleName=agentcore_gateway_role_name,
            AssumeRolePolicyDocument=assume_role_policy_document_json,
        )

        # Pause to make sure role is created
        time.sleep(10)
    except iam_client.exceptions.EntityAlreadyExistsException:
        logger.info(
            f"Role {agentcore_gateway_role_name} already exists, deleting and recreating"
        )
        policies = iam_client.list_role_policies(
            RoleName=agentcore_gateway_role_name, MaxItems=100
        )
        for policy_name in policies["PolicyNames"]:
            iam_client.delete_role_policy(
                RoleName=agentcore_gateway_role_name, PolicyName=policy_name
            )
        iam_client.delete_role(RoleName=agentcore_gateway_role_name)
        agentcore_iam_role = iam_client.create_role(
            RoleName=agentcore_gateway_role_name,
            AssumeRolePolicyDocument=assume_role_policy_document_json,
        )

    logger.info(
        f"Attaching inline policy AgentCorePolicy to {agentcore_gateway_role_name}"
    )
    try:
        iam_client.put_role_policy(
            PolicyDocument=role_policy_document,
            PolicyName="AgentCorePolicy",
            RoleName=agentcore_gateway_role_name,
        )
    except Exception as e:
        logger.warning(f"Put role policy failed: {e}")

    return agentcore_iam_role


def create_gateway_lambda(lambda_function_code_path: str) -> dict[str, str | int]:
    return_resp = {"lambda_function_arn": "Pending", "exit_code": 1}

    # Initialize Cognito client
    lambda_client = boto3.client("lambda", region_name=DEFAULT_REGION)
    iam_client = boto3.client("iam", region_name=DEFAULT_REGION)

    role_name = "gateway_lambda_iamrole"
    role_arn = ""
    lambda_function_name = "gateway_lambda"

    logger.info("Reading code from zip file")
    with open(lambda_function_code_path, "rb") as f:
        lambda_function_code = f.read()

    try:
        logger.info("Creating IAM role for lambda function")

        response = iam_client.create_role(
            RoleName=role_name,
            AssumeRolePolicyDocument=json.dumps(
                {
                    "Version": "2012-10-17",
                    "Statement": [
                        {
                            "Effect": "Allow",
                            "Principal": {"Service": "lambda.amazonaws.com"},
                            "Action": "sts:AssumeRole",
                        }
                    ],
                }
            ),
            Description="IAM role to be assumed by lambda function",
        )

        role_arn = response["Role"]["Arn"]

        logger.info("Attaching policy to the IAM role")

        response = iam_client.attach_role_policy(
            RoleName=role_name,
            PolicyArn="arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole",
        )

        logger.info(f"Role '{role_name}' created successfully: {role_arn}")
    except ClientError as error:
        if error.response["Error"]["Code"] == "EntityAlreadyExists":
            response = iam_client.get_role(RoleName=role_name)
            role_arn = response["Role"]["Arn"]
            logger.info(
                f"IAM role {role_name} already exists. Using the same ARN {role_arn}"
            )
        else:
            error_message = (
                error.response["Error"]["Code"]
                + "-"
                + error.response["Error"]["Message"]
            )
            logger.info(f"Error creating role: {error_message}")
            return_resp["lambda_function_arn"] = error_message

    if role_arn != "":
        logger.info("Creating lambda function")
        # Create lambda function
        try:
            lambda_response = lambda_client.create_function(
                FunctionName=lambda_function_name,
                Role=role_arn,
                Runtime="python3.12",
                Handler="lambda_function_code.lambda_handler",
                Code={"ZipFile": lambda_function_code},
                Description="Lambda function example for Bedrock AgentCore Gateway",
                PackageType="Zip",
            )

            return_resp["lambda_function_arn"] = lambda_response["FunctionArn"]
            return_resp["exit_code"] = 0
        except ClientError as error:
            if error.response["Error"]["Code"] == "ResourceConflictException":
                response = lambda_client.get_function(FunctionName=lambda_function_name)
                lambda_arn = response["Configuration"]["FunctionArn"]
                logger.info(
                    f"AWS Lambda function {lambda_function_name} already exists. Using the same ARN {lambda_arn}"
                )
                return_resp["lambda_function_arn"] = lambda_arn
            else:
                error_message = (
                    error.response["Error"]["Code"]
                    + "-"
                    + error.response["Error"]["Message"]
                )
                logger.info(f"Error creating lambda function: {error_message}")
                return_resp["lambda_function_arn"] = error_message

    return return_resp


def delete_gateway(gateway_client: Any, gateway_id: str) -> None:
    """Delete all targets then the gateway. Retries until no targets remain (deletes can be async)."""
    logger.info(f"Deleting all targets for gateway {gateway_id}")
    for _ in range(10):  # retry loop in case target deletes are async
        list_response = gateway_client.list_gateway_targets(
            gatewayIdentifier=gateway_id, maxResults=100
        )
        items = list_response.get("items", [])
        # Paginate if there is nextToken
        next_token = list_response.get("nextToken")
        while next_token:
            page = gateway_client.list_gateway_targets(
                gatewayIdentifier=gateway_id, maxResults=100, nextToken=next_token
            )
            items.extend(page.get("items", []))
            next_token = page.get("nextToken")
        if not items:
            break
        for item in items:
            target_id = item["targetId"]
            logger.info(f"Deleting target {target_id}")
            gateway_client.delete_gateway_target(
                gatewayIdentifier=gateway_id, targetId=target_id
            )
        time.sleep(2)
    logger.info(f"Deleting gateway {gateway_id}")
    gateway_client.delete_gateway(gatewayIdentifier=gateway_id)


def delete_all_gateways(gateway_client: Any) -> None:
    try:
        list_response = gateway_client.list_gateways(maxResults=100)
        for item in list_response["items"]:
            gatewayId = item["gatewayId"]
            delete_gateway(gateway_client, gatewayId)
    except Exception as e:
        logger.warning(f"List/delete gateways failed: {e}")


# --- Cleanup helpers (order is reverse of deploy) ---


def delete_gateway_by_name(gateway_name: str, region: str = DEFAULT_REGION) -> None:
    """Delete gateway and its targets by gateway name. No-op if not found."""
    gateway_client = boto3.client("bedrock-agentcore-control", region_name=region)
    list_response = gateway_client.list_gateways(maxResults=100)
    for item in list_response.get("items", []):
        if item.get("name") == gateway_name:
            delete_gateway(gateway_client, item["gatewayId"])
            return


def delete_api_key_provider_by_name(
    credential_provider_name: str, region: str = DEFAULT_REGION
) -> None:
    """Delete API key credential provider by name. No-op if not found or delete not supported."""
    client = boto3.client("bedrock-agentcore-control", region_name=region)
    delete_method = getattr(client, "delete_api_key_credential_provider", None)
    if delete_method is None:
        return
    try:
        delete_method(name=credential_provider_name)
    except ClientError:
        pass


def delete_user_pool_by_name(user_pool_name: str, region: str = DEFAULT_REGION) -> None:
    """Delete Cognito user pool by name. Removes domain first if present. No-op if not found."""
    cognito_client = boto3.client("cognito-idp", region_name=region)
    response = cognito_client.list_user_pools(MaxResults=60)
    for pool in response.get("UserPools", []):
        if pool.get("Name") != user_pool_name:
            continue
        pool_id = pool["Id"]
        desc = cognito_client.describe_user_pool(UserPoolId=pool_id)
        domain = desc.get("UserPool", {}).get("Domain")
        if domain:
            cognito_client.delete_user_pool_domain(UserPoolId=pool_id, Domain=domain)
        cognito_client.delete_user_pool(UserPoolId=pool_id)
        return


def delete_iam_role_by_name(role_name: str) -> None:
    """Detach inline policies and delete IAM role. No-op if not found."""
    iam_client = boto3.client("iam")
    try:
        iam_client.get_role(RoleName=role_name)
    except ClientError as e:
        if e.response["Error"]["Code"] in ("NoSuchEntity", "ResourceNotFoundException"):
            return
        raise
    for policy_name in iam_client.list_role_policies(
        RoleName=role_name, MaxItems=100
    ).get("PolicyNames", []):
        iam_client.delete_role_policy(RoleName=role_name, PolicyName=policy_name)
    iam_client.delete_role(RoleName=role_name)


def run_cleanup(
    gateway_name: str,
    gateway_role_name: str,
    user_pool_name: str,
    credential_provider_name: str,
    region: str = DEFAULT_REGION,
) -> None:
    """Delete all gateway resources (gateway, API key provider, user pool, IAM role)."""
    try:
        delete_gateway_by_name(gateway_name, region)
    except Exception as e:
        logger.warning(f"Cleanup gateway failed: {e}")
    try:
        delete_api_key_provider_by_name(credential_provider_name, region)
    except Exception as e:
        logger.warning(f"Cleanup API key provider failed: {e}")
    try:
        delete_user_pool_by_name(user_pool_name, region)
    except Exception as e:
        logger.warning(f"Cleanup user pool failed: {e}")
    role_name = f"agentcore-{gateway_role_name}-role"
    try:
        delete_iam_role_by_name(role_name)
    except Exception as e:
        logger.warning(f"Cleanup IAM role failed: {e}")

